126→/// Extracted function signature for harness generation.
127→struct FnSignature {
128→    param_names: Vec<String>,
129→    param_types: Vec<String>,
130→    return_type: Option<String>,
131→}
132→
133→/// Extract parameter info from a Rust source file for a specific function.
134→fn extract_fn_signature(
135→    source: &str,
136→    function_name: &str,
137→) -> Result<FnSignature, ExecuteError> {
138→    use quote::ToTokens;
139→
140→    let file = syn::parse_file(source)
141→        .map_err(|e| ExecuteError::InstrumentError(format!("parse error: {e}")))?;
142→
143→    for item in &file.items {
144→        if let syn::Item::Fn(item_fn) = item
145→            && item_fn.sig.ident == function_name
146→        {
147→            let mut param_names = Vec::new();
148→            let mut param_types = Vec::new();
149→
150→            for arg in &item_fn.sig.inputs {
151→                if let syn::FnArg::Typed(pat_type) = arg {
152→                    let name = pat_type.pat.to_token_stream().to_string();
153→                    let ty = pat_type.ty.to_token_stream().to_string();
154→                    param_names.push(name);
155→                    param_types.push(ty);
156→                }
157→            }
158→
159→            let return_type = match &item_fn.sig.output {
160→                syn::ReturnType::Default => None,
161→                syn::ReturnType::Type(_, ty) => Some(ty.to_token_stream().to_string()),
162→            };
163→
164→            return Ok(FnSignature { param_names, param_types, return_type });
165→        }
166→    }
167→
168→    Err(ExecuteError::InstrumentError(format!(
169→        "function not found: {function_name}"
170→    )))
171→}
