173→/// Generate a Cargo.toml for the temp project.
174→fn generate_cargo_toml(runtime_path: &Path) -> String {
175→    let runtime_path_str = runtime_path.display().to_string().replace('\\', "/");
176→    format!(
177→        r#"[package]
178→name = "shatter-exec-temp"
179→version = "0.1.0"
180→edition = "2021"
181→
182→[dependencies]
183→serde = {{ version = "1", features = ["derive"] }}
184→serde_json = "1"
185→shatter-rust-runtime = {{ path = "{runtime_path_str}" }}
186→"#
187→    )
188→}
