  1→//! Source-to-source instrumentor for Rust code.
  2→//!
  3→//! Parses Rust source files using `syn`, walks the AST to find branch points
  4→//! (`if`, `match`, `while`/`for`) and external function calls, then emits
  5→//! instrumented source code using `quote` that calls into `shatter_rust_runtime`.
  6→//!
  7→//! ## Instrumentation strategy
  8→//!
  9→//! - **Branch points**: For each `if`/`while`/`for` condition, wrap the condition
 10→//!   in a closure that records the branch decision via `shatter_rust_runtime::branch_hit`.
 11→//!   For `match` arms, insert a `branch_hit` call at the top of each arm body.
 12→//!
 13→//! - **External calls**: For function calls to symbols not defined in the file,
 14→//!   wrap them in a `shatter_rust_runtime::mock_call` check that can intercept
 15→//!   and replace return values.
 16→
 17→use std::path::Path;
 18→
 19→use proc_macro2::TokenStream;
 20→use quote::{quote, ToTokens};
 21→use syn::visit_mut::VisitMut;
 22→use syn::{parse_file, Expr, ExprIf, ExprMatch, ExprWhile, ExprForLoop, Stmt};
 23→
 24→/// Errors that can occur during instrumentation.
 25→#[derive(Debug)]
 26→pub enum InstrumentError {
 27→    FileNotFound(String),
 28→    ReadError(String),
 29→    ParseError(String),
 30→}
 31→
 32→impl std::fmt::Display for InstrumentError {
 33→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 34→        match self {
 35→            Self::FileNotFound(p) => write!(f, "file not found: {p}"),
 36→            Self::ReadError(e) => write!(f, "failed to read file: {e}"),
 37→            Self::ParseError(e) => write!(f, "failed to parse file: {e}"),
 38→        }
 39→    }
 40→}
 41→
 42→/// Result of instrumenting a source file.
 43→#[derive(Debug)]
 44→pub struct InstrumentResult {
 45→    /// The instrumented source code as a string.
 46→    pub source: String,
 47→    /// Number of branch points instrumented.
 48→    pub branch_count: u32,
 49→}
 50→
 51→/// Instrument a Rust source file, optionally targeting a single function.
 52→///
 53→/// Returns the instrumented source code and the number of branches found.
 54→pub fn instrument_file(
 55→    path: &Path,
 56→    function_name: Option<&str>,
 57→) -> Result<InstrumentResult, InstrumentError> {
 58→    if !path.exists() {
 59→        return Err(InstrumentError::FileNotFound(
 60→            path.display().to_string(),
 61→        ));
 62→    }
 63→
 64→    let source = std::fs::read_to_string(path)
 65→        .map_err(|e| InstrumentError::ReadError(e.to_string()))?;
 66→
 67→    instrument_source(&source, function_name)
 68→}
 69→
 70→/// Instrument Rust source code from a string.
 71→pub fn instrument_source(
 72→    source: &str,
 73→    function_name: Option<&str>,
 74→) -> Result<InstrumentResult, InstrumentError> {
 75→    let mut syntax = parse_file(source)
 76→        .map_err(|e| InstrumentError::ParseError(e.to_string()))?;
 77→
 78→    let mut visitor = Instrumentor::new(function_name);
 79→    visitor.visit_file_mut(&mut syntax);
 80→
 81→    let output = syntax.to_token_stream().to_string();
 82→
 83→    Ok(InstrumentResult {
 84→        source: output,
 85→        branch_count: visitor.branch_id,
 86→    })
 87→}
 88→
 89→/// AST visitor that rewrites branch conditions and external calls.
 90→struct Instrumentor {
 91→    /// Next branch ID to assign.
 92→    branch_id: u32,
 93→    /// If set, only instrument this function.
 94→    target_function: Option<String>,
 95→    /// Whether we are currently inside the target function.
 96→    inside_target: bool,
 97→    /// Approximate line number tracker (updated as we traverse).
 98→    current_line: u32,
 99→}
100→
101→impl Instrumentor {
102→    fn new(target_function: Option<&str>) -> Self {
103→        Self {
104→            branch_id: 0,
105→            target_function: target_function.map(String::from),
106→            inside_target: target_function.is_none(), // if no target, always active
107→            current_line: 0,
108→        }
109→    }
110→
111→    /// Allocate and return the next branch ID.
112→    fn next_branch_id(&mut self) -> u32 {
113→        let id = self.branch_id;
114→        self.branch_id += 1;
115→        id
116→    }
117→
118→    /// Get the line number for an expression using its span.
119→    fn line_of(&self, expr: &impl syn::spanned::Spanned) -> u32 {
120→        let span = expr.span();
121→        let start = span.start();
122→        // proc_macro2 line numbers are 1-based when span-locations feature is enabled
123→        if start.line > 0 {
124→            start.line as u32
125→        } else {
126→            self.current_line
127→        }
128→    }
129→
130→    /// Create a branch_hit wrapper expression that evaluates the condition,
131→    /// records the branch, and returns the condition value.
132→    ///
133→    /// Generates:
134→    /// ```ignore
135→    /// {
136→    ///     let __shatter_cond = <condition>;
137→    ///     shatter_rust_runtime::branch_hit(<id>, <line>, __shatter_cond, <constraint_json>);
138→    ///     __shatter_cond
139→    /// }
140→    /// ```
141→    fn wrap_condition(&mut self, cond: &Expr) -> Expr {
142→        let id = self.next_branch_id();
143→        let line = self.line_of(cond);
144→        let constraint_json = constraint_for_expr(cond);
145→
146→        let tokens: TokenStream = quote! {
147→            {
148→                let __shatter_cond = #cond;
149→                shatter_rust_runtime::branch_hit(#id, #line, __shatter_cond, #constraint_json);
150→                __shatter_cond
151→            }
152→        };
153→
154→        syn::parse2(tokens).unwrap_or_else(|_| cond.clone())
155→    }
156→
157→    /// Create a branch_hit statement for a match arm body.
158→    ///
159→    /// Generates:
160→    /// ```ignore
161→    /// shatter_rust_runtime::branch_hit(<id>, <line>, true, <constraint_json>);
162→    /// ```
163→    fn branch_hit_stmt(&mut self, line: u32, constraint_json: &str) -> Stmt {
164→        let id = self.next_branch_id();
165→        let tokens: TokenStream = quote! {
166→            shatter_rust_runtime::branch_hit(#id, #line, true, #constraint_json);
167→        };
168→
169→        syn::parse2(tokens).unwrap_or_else(|_| {
170→            // Fallback: empty statement
171→            syn::parse2(quote! { ; }).expect("semicolon should parse")
172→        })
173→    }
174→}
175→
176→impl VisitMut for Instrumentor {
177→    fn visit_item_fn_mut(&mut self, node: &mut syn::ItemFn) {
178→        let fn_name = node.sig.ident.to_string();
179→        let was_inside = self.inside_target;
180→
181→        if let Some(ref target) = self.target_function {
182→            if &fn_name == target {
183→                self.inside_target = true;
184→            } else {
185→                // Skip functions that aren't our target
186→                return;
187→            }
188→        } else {
189→            self.inside_target = true;
190→        }
191→
192→        // Visit the function body
193→        syn::visit_mut::visit_item_fn_mut(self, node);
194→
195→        self.inside_target = was_inside;
196→    }
197→
198→    fn visit_impl_item_fn_mut(&mut self, node: &mut syn::ImplItemFn) {
199→        let fn_name = node.sig.ident.to_string();
200→        let was_inside = self.inside_target;
201→
202→        if let Some(ref target) = self.target_function {
203→            if &fn_name == target {
204→                self.inside_target = true;
205→            } else {
206→                return;
207→            }
208→        } else {
209→            self.inside_target = true;
210→        }
211→
212→        syn::visit_mut::visit_impl_item_fn_mut(self, node);
213→
214→        self.inside_target = was_inside;
215→    }
216→
217→    fn visit_expr_if_mut(&mut self, node: &mut ExprIf) {
218→        if !self.inside_target {
219→            return;
220→        }
221→
222→        // Wrap the condition
223→        let wrapped = self.wrap_condition(&node.cond);
224→        *node.cond = wrapped;
225→
226→        // Continue visiting the then/else branches
227→        syn::visit_mut::visit_expr_if_mut(self, node);
228→    }
229→
230→    fn visit_expr_while_mut(&mut self, node: &mut ExprWhile) {
231→        if !self.inside_target {
232→            return;
233→        }
234→
235→        let wrapped = self.wrap_condition(&node.cond);
236→        *node.cond = wrapped;
237→
238→        syn::visit_mut::visit_expr_while_mut(self, node);
239→    }
240→
241→    fn visit_expr_for_loop_mut(&mut self, node: &mut ExprForLoop) {
242→        if !self.inside_target {
243→            return;
244→        }
245→
246→        // For loops don't have a boolean condition, but we can record
247→        // entry into the loop body as a branch point
248→        let line = self.line_of(node);
249→        let constraint_json = format!(
250→            r#"{{"kind":"unknown","hint":"for loop over {}"}}"#,
251→            node.expr.to_token_stream()
252→        );
253→        let stmt = self.branch_hit_stmt(line, &constraint_json);
254→        node.body.stmts.insert(0, stmt);
255→
256→        syn::visit_mut::visit_expr_for_loop_mut(self, node);
257→    }
258→
259→    fn visit_expr_match_mut(&mut self, node: &mut ExprMatch) {
260→        if !self.inside_target {
261→            return;
262→        }
263→
264→        let match_expr_tokens = node.expr.to_token_stream().to_string();
265→
266→        for arm in &mut node.arms {
267→            let line = self.line_of(&arm.pat);
268→            let pattern_str = arm.pat.to_token_stream().to_string();
269→            let constraint_json = format!(
270→                r#"{{"kind":"bin_op","op":"eq","left":{{"kind":"param","name":"{}"}},"right":{{"kind":"const","type":"str","value":"{}"}}}}"#,
271→                escape_json_string(&match_expr_tokens),
272→                escape_json_string(&pattern_str),
273→            );
274→
275→            let id = self.next_branch_id();
276→            let branch_line = line;
277→
278→            // We need to wrap the arm body to include the branch_hit call.
279→            // The arm body is an Expr — wrap it in a block if needed.
280→            let body = &arm.body;
281→            let tokens: TokenStream = quote! {
282→                {
283→                    shatter_rust_runtime::branch_hit(#id, #branch_line, true, #constraint_json);
284→                    #body
285→                }
286→            };
287→
288→            if let Ok(new_body) = syn::parse2::<Expr>(tokens) {
289→                *arm.body = new_body;
290→            }
291→        }
292→
293→        syn::visit_mut::visit_expr_match_mut(self, node);
294→    }
295→}
296→
297→/// Build a JSON constraint string from a condition expression.
298→fn constraint_for_expr(expr: &Expr) -> String {
299→    match expr {
300→        Expr::Binary(bin) => {
301→            let op = match bin.op {
302→                syn::BinOp::Eq(_) => "eq",
303→                syn::BinOp::Ne(_) => "ne",
304→                syn::BinOp::Lt(_) => "lt",
305→                syn::BinOp::Le(_) => "le",
306→                syn::BinOp::Gt(_) => "gt",
307→                syn::BinOp::Ge(_) => "ge",
308→                syn::BinOp::And(_) => "and",
309→                syn::BinOp::Or(_) => "or",
310→                _ => {
311→                    return format!(
312→                        r#"{{"kind":"unknown","hint":"{}"}}"#,
313→                        escape_json_string(&expr.to_token_stream().to_string())
314→                    );
315→                }
316→            };
317→            let left = constraint_for_operand(&bin.left);
318→            let right = constraint_for_operand(&bin.right);
319→            format!(
320→                r#"{{"kind":"bin_op","op":"{}","left":{},"right":{}}}"#,
321→                op, left, right
322→            )
323→        }
324→        Expr::Unary(un) => {
325→            let op = match un.op {
326→                syn::UnOp::Not(_) => "not",
327→                syn::UnOp::Neg(_) => "neg",
328→                _ => {
329→                    return format!(
330→                        r#"{{"kind":"unknown","hint":"{}"}}"#,
331→                        escape_json_string(&expr.to_token_stream().to_string())
332→                    );
333→                }
334→            };
335→            let operand = constraint_for_operand(&un.expr);
336→            format!(
337→                r#"{{"kind":"un_op","op":"{}","operand":{}}}"#,
338→                op, operand
339→            )
340→        }
341→        Expr::Path(path) => {
342→            let name = path.to_token_stream().to_string();
343→            format!(r#"{{"kind":"param","name":"{}","path":[]}}"#, escape_json_string(&name))
344→        }
345→        Expr::Lit(lit) => constraint_for_lit(lit),
346→        Expr::MethodCall(mc) => {
347→            let name = mc.method.to_string();
348→            format!(
349→                r#"{{"kind":"unknown","hint":"method call: {}"}}"#,
350→                escape_json_string(&name)
351→            )
352→        }
353→        Expr::Call(call) => {
354→            let name = call.func.to_token_stream().to_string();
355→            format!(
356→                r#"{{"kind":"unknown","hint":"call: {}"}}"#,
357→                escape_json_string(&name)
358→            )
359→        }
360→        _ => {
361→            format!(
362→                r#"{{"kind":"unknown","hint":"{}"}}"#,
363→                escape_json_string(&expr.to_token_stream().to_string())
364→            )
365→        }
366→    }
367→}
368→
369→/// Build a constraint JSON for a single operand (leaf node).
370→fn constraint_for_operand(expr: &Expr) -> String {
371→    match expr {
372→        Expr::Path(path) => {
373→            let name = path.to_token_stream().to_string();
374→            format!(r#"{{"kind":"param","name":"{}","path":[]}}"#, escape_json_string(&name))
375→        }
376→        Expr::Lit(lit) => constraint_for_lit(lit),
377→        // For compound expressions, recurse
378→        Expr::Binary(_) | Expr::Unary(_) => constraint_for_expr(expr),
379→        _ => {
380→            format!(
381→                r#"{{"kind":"unknown","hint":"{}"}}"#,
382→                escape_json_string(&expr.to_token_stream().to_string())
383→            )
384→        }
385→    }
386→}
387→
388→/// Build a constraint JSON for a literal expression.
389→fn constraint_for_lit(lit: &syn::ExprLit) -> String {
390→    match &lit.lit {
391→        syn::Lit::Int(i) => {
392→            format!(r#"{{"kind":"const","type":"int","value":{}}}"#, i.base10_digits())
393→        }
394→        syn::Lit::Float(f) => {
395→            format!(r#"{{"kind":"const","type":"float","value":{}}}"#, f.base10_digits())
396→        }
397→        syn::Lit::Str(s) => {
398→            format!(
399→                r#"{{"kind":"const","type":"str","value":"{}"}}"#,
400→                escape_json_string(&s.value())
401→            )
402→        }
403→        syn::Lit::Bool(b) => {
404→            format!(r#"{{"kind":"const","type":"bool","value":{}}}"#, b.value)
405→        }
406→        _ => {
407→            format!(
408→                r#"{{"kind":"unknown","hint":"literal: {}"}}"#,
409→                escape_json_string(&lit.to_token_stream().to_string())
410→            )
411→        }
412→    }
413→}
414→
415→/// Escape a string for safe inclusion in JSON.
416→fn escape_json_string(s: &str) -> String {
417→    s.replace('\\', "\\\\")
418→        .replace('"', "\\\"")
419→        .replace('\n', "\\n")
420→        .replace('\r', "\\r")
421→        .replace('\t', "\\t")
422→}
