  1→use std::collections::HashMap;
  2→use std::sync::Mutex;
  3→
  4→/// Result returned by compiled-in (custom build) native generators.
  5→/// Value holds a live in-process object; recipe is a serializable blob for replay.
  6→pub struct GeneratorResult {
  7→    pub id: String,
  8→    pub value: Box<dyn std::any::Any + Send>,
  9→    pub recipe: serde_json::Value,
 10→}
 11→
 12→/// Signature for custom-build native generator functions.
 13→pub type NativeGeneratorFn = Box<dyn Fn(Option<serde_json::Value>) -> GeneratorResult + Send + Sync>;
 14→
 15→/// Stores live (non-serializable) objects returned by native generators.
 16→/// Core receives a sentinel JSON referencing the handle; the frontend resolves
 17→/// it to the live object during execution.
 18→pub struct HandleTable {
 19→    handles: Mutex<HandleTableInner>,
 20→}
 21→
 22→struct HandleTableInner {
 23→    map: HashMap<String, Box<dyn std::any::Any + Send>>,
 24→    next_id: u32,
 25→}
 26→
 27→impl Default for HandleTable {
 28→    fn default() -> Self {
 29→        Self::new()
 30→    }
 31→}
 32→
 33→impl HandleTable {
 34→    pub fn new() -> Self {
 35→        Self {
 36→            handles: Mutex::new(HandleTableInner {
 37→                map: HashMap::new(),
 38→                next_id: 0,
 39→            }),
 40→        }
 41→    }
 42→
 43→    /// Store a live value and return a unique handle ID.
 44→    pub fn store(&self, val: Box<dyn std::any::Any + Send>) -> String {
 45→        let mut inner = self.handles.lock().expect("handle table lock poisoned");
 46→        inner.next_id += 1;
 47→        let id = format!("h_{:04}", inner.next_id);
 48→        inner.map.insert(id.clone(), val);
 49→        id
 50→    }
 51→
 52→    /// Resolve a handle to its live value, removing it from the table.
 53→    pub fn take(&self, id: &str) -> Option<Box<dyn std::any::Any + Send>> {
 54→        let mut inner = self.handles.lock().expect("handle table lock poisoned");
 55→        inner.map.remove(id)
 56→    }
 57→
 58→    /// Clear all handles. Call between exploration runs.
 59→    pub fn clear(&self) {
 60→        let mut inner = self.handles.lock().expect("handle table lock poisoned");
 61→        inner.map.clear();
 62→        inner.next_id = 0;
 63→    }
 64→
 65→    /// Number of stored handles.
 66→    pub fn len(&self) -> usize {
 67→        self.handles.lock().expect("handle table lock poisoned").map.len()
 68→    }
 69→
 70→    /// Whether the table is empty.
 71→    pub fn is_empty(&self) -> bool {
 72→        self.len() == 0
 73→    }
 74→}
 75→
 76→/// Registry dispatches generate requests to WASM plugins or native generators.
 77→pub struct NativeRegistry {
 78→    generators: HashMap<String, NativeGeneratorFn>,
 79→    pub handles: HandleTable,
 80→}
 81→
 82→impl Default for NativeRegistry {
 83→    fn default() -> Self {
 84→        Self::new()
 85→    }
 86→}
 87→
 88→impl NativeRegistry {
 89→    pub fn new() -> Self {
 90→        Self {
 91→            generators: HashMap::new(),
 92→            handles: HandleTable::new(),
 93→        }
 94→    }
 95→
 96→    /// Register a compiled-in generator function by name.
 97→    pub fn register(&mut self, name: impl Into<String>, func: NativeGeneratorFn) {
 98→        self.generators.insert(name.into(), func);
 99→    }
