313→    fn handle_execute(&self, mut resp: Response, req: &Request) -> Response {
314→        let file_path = match req.file.as_ref().or(self.last_file.as_ref()) {
315→            Some(f) => f,
316→            None => {
317→                resp.status = "error".to_string();
