396→                return resp;
397→            }
398→        };
399→        let scope = match &req.scope {
400→            Some(s) => s.as_str(),
401→            None => {
402→                resp.status = "error".to_string();
403→                resp.code = Some("invalid_request".to_string());
404→                resp.message = Some("setup command requires a scope".to_string());
405→                return resp;
406→            }
407→        };
408→
409→        let path = std::path::Path::new(file_path);
410→        match crate::setup::run_setup(path, level, scope, req.parent_context.as_ref()) {
411→            Ok(result) => {
412→                resp.status = "setup".to_string();
413→                resp.setup_context = Some(result.context);
414→                resp
415→            }
416→            Err(crate::setup::SetupError::FileNotFound(_)) => {
417→                resp.status = "error".to_string();
418→                resp.code = Some("file_not_found".to_string());
419→                resp.message = Some(format!("setup file not found: {file_path}"));
420→                resp
421→            }
422→            Err(crate::setup::SetupError::CompilationFailed(msg)) => {
423→                resp.status = "error".to_string();
424→                resp.code = Some("compilation_error".to_string());
425→                resp.message = Some(msg);
426→                resp
427→            }
428→            Err(e) => {
429→                resp.status = "error".to_string();
430→                resp.code = Some("internal_error".to_string());
431→                resp.message = Some(e.to_string());
432→                resp
433→            }
434→        }
435→    }
436→
437→    fn handle_teardown(&self, mut resp: Response, req: &Request) -> Response {
438→        let level = match &req.level {
439→            Some(l) => *l,
440→            None => {
441→                resp.status = "error".to_string();
442→                resp.code = Some("invalid_request".to_string());
443→                resp.message = Some("teardown command requires a level".to_string());
444→                return resp;
445→            }
446→        };
447→        let scope = match &req.scope {
448→            Some(s) => s.as_str(),
449→            None => {
450→                resp.status = "error".to_string();
451→                resp.code = Some("invalid_request".to_string());
452→                resp.message = Some("teardown command requires a scope".to_string());
453→                return resp;
454→            }
455→        };
456→
457→        match crate::setup::run_teardown(level, scope) {
458→            Ok(()) => {
459→                resp.status = "teardown".to_string();
460→                resp
461→            }
462→            Err(e) => {
463→                resp.status = "error".to_string();
464→                resp.code = Some("internal_error".to_string());
465→                resp.message = Some(e.to_string());
466→                resp
467→            }
468→        }
469→    }
470→
471→    fn handle_generate(&mut self, mut resp: Response, req: &Request) -> Response {
472→        let file_path = match &req.file {
473→            Some(f) => f,
474→            None => {
475→                resp.status = "error".to_string();
476→                resp.code = Some("invalid_request".to_string());
477→                resp.message = Some("generate command requires a file path".to_string());
478→                return resp;
479→            }
480→        };
481→        let func_name = match &req.name {
482→            Some(n) => n.clone(),
483→            None => {
484→                resp.status = "error".to_string();
485→                resp.code = Some("invalid_request".to_string());
486→                resp.message = Some("generate command requires a name".to_string());
487→                return resp;
488→            }
489→        };
490→
491→        let path = std::path::Path::new(file_path);
492→        let ext = path.extension().and_then(|e| e.to_str());
493→
494→        match ext {
495→            Some("wasm") => {
496→                match self.wasm_cache.generate(path, &func_name, req.recipe.as_ref()) {
497→                    Ok((value, generator_id, recipe)) => {
498→                        resp.status = "generate".to_string();
499→                        resp.value = Some(value);
500→                        resp.generator_id = Some(generator_id);
501→                        resp.recipe = recipe;
502→                        resp
503→                    }
504→                    Err(e) => {
505→                        resp.status = "error".to_string();
506→                        resp.code = Some("internal_error".to_string());
507→                        resp.message = Some(e);
508→                        resp
509→                    }
510→                }
511→            }
512→            Some("rs") => {
513→                if let Some(ref registry) = self.native_registry {
514→                    match registry.generate(&func_name, req.recipe.clone()) {
515→                        Ok((value, generator_id, recipe)) => {
516→                            resp.status = "generate".to_string();
517→                            resp.value = Some(value);
518→                            resp.generator_id = Some(generator_id);
519→                            resp.recipe = Some(recipe);
520→                            resp
521→                        }
522→                        Err(e) => {
523→                            resp.status = "error".to_string();
524→                            resp.code = Some("internal_error".to_string());
525→                            resp.message = Some(e);
526→                            resp
527→                        }
528→                    }
529→                } else {
530→                    resp.status = "error".to_string();
531→                    resp.code = Some("internal_error".to_string());
532→                    resp.message = Some(format!(
533→                        "native generator {func_name:?} requires a custom build (run `shatter build-frontend rust`)"
534→                    ));
535→                    resp
536→                }
537→            }
538→            _ => {
539→                resp.status = "error".to_string();
540→                resp.code = Some("invalid_request".to_string());
541→                resp.message = Some(format!(
542→                    "unsupported generator file type: {}",
543→                    file_path
544→                ));
545→                resp
546→            }
547→        }
548→    }
